Google.Chrome.DetectionScript:
$paths = @('HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall\*','HKLM:\SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall\*')
$apps = foreach ($path in $paths) { Get-ItemProperty -Path $path -ErrorAction SilentlyContinue }
if ($apps | Where-Object { $_.DisplayName -like '*Google Chrome*' }) { exit 0 }
exit 1

